import Link from 'next/link';

export default function ProfilePage() {
  const router = useRouter();
  const [user, setUser] = useState<any>(null);
  const [orders, setOrders] = useState<any[]>([]);
  const [wallet, setWallet] = useState<any>({ balance: 0, topUps: [] });
  const [activeTab, setActiveTab] = useState('orders');
  const [loading, setLoading] = useState(true);

  const [topupAmount, setTopupAmount] = useState('');
  const [screenshotFile, setScreenshotFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (!token || !userData) {
      router.push('/login');
      return;
    }

    setUser(JSON.parse(userData));

    Promise.all([
      fetch('http://localhost:4000/api/user/orders', {
        headers: { 'Authorization': `Bearer ${token}` }
      }).then(res => res.json()),
      fetch('http://localhost:4000/api/wallet', {
        headers: { 'Authorization': `Bearer ${token}` }
      }).then(res => res.json())
    ])
      .then(([ordersData, walletData]) => {
        if (Array.isArray(ordersData)) {
          setOrders(ordersData);
        }
        if (walletData && !walletData.error) {
          setWallet(walletData);
        }
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [router]);

  const handleTopupSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topupAmount || !screenshotFile) return;

    setUploading(true);
    const formData = new FormData();
    formData.append('amount', topupAmount);
    formData.append('screenshot', screenshotFile);

    try {
      const res = await fetch('http://localhost:4000/api/wallet/topup', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: formData
      });
      const data = await res.json();
      if (data.success) {
        alert('Top-up request submitted successfully!');
        setTopupAmount('');
        setScreenshotFile(null);
        // Refresh wallet data
        const walletRes = await fetch('http://localhost:4000/api/wallet', {
          headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
        });
        const walletData = await walletRes.json();
        if (walletData && !walletData.error) setWallet(walletData);
      } else {
        alert(data.error || 'Failed to submit top-up request');
      }
    } catch (err) {
      console.error(err);
      alert('An error occurred');
    } finally {
      setUploading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    router.push('/login');
  };

  if (loading) {
    return <div className="min-h-[60vh] flex items-center justify-center text-shakti-dark font-bold text-xl">Loading your profile...</div>;
  }

  return (
    <div className="max-w-5xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row gap-8">

        {/* Sidebar */}
        <div className="md:w-1/3">
          <div className="bg-white rounded-[2rem] p-8 shadow-sm border border-shakti-mitti/10 sticky top-24">
            <div className="w-20 h-20 bg-shakti-sarson rounded-full text-shakti-rust flex items-center justify-center text-3xl font-black mb-6">
              {user?.name?.[0]?.toUpperCase() || 'U'}
            </div>
            <h2 className="text-2xl font-black text-shakti-dark mb-1">{user?.name}</h2>
            <p className="text-shakti-mitti font-medium mb-8">{user?.email}</p>

            <div className="space-y-2">
              <button 
                onClick={() => setActiveTab('orders')}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-colors ${activeTab === 'orders' ? 'bg-shakti-cream text-shakti-dark' : 'text-shakti-mitti hover:bg-shakti-cream/50'}`}>
