                <Wallet className={`w-5 h-5 ${activeTab === 'wallet' ? 'text-shakti-rust' : ''}`} />
                Wallet
              </button>
              <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-red-50 text-red-500 font-bold transition-colors">
