'use client';

import Link from 'next/link';
import { ShoppingCart, Search, Menu, User } from 'lucide-react';
import { usePathname } from 'next/navigation';
import { useState, useEffect } from 'react';

export default function Navbar({ isLoggedIn = false }: { isLoggedIn?: boolean }) {
  const pathname = usePathname();
  const [cartCount, setCartCount] = useState(0);

  useEffect(() => {
    const updateCount = () => {
      const saved = localStorage.getItem('shakti_cart');
      if (saved) {
        try {
          const items = JSON.parse(saved);
          const count = items.reduce((acc: number, item: any) => acc + item.quantity, 0);
          setCartCount(count);
        } catch (e) {}
      }
    };

    updateCount();
    window.addEventListener('storage', updateCount);
    // Custom event for same-window updates
    window.addEventListener('cartUpdated', updateCount);

    return () => {
      window.removeEventListener('storage', updateCount);
      window.removeEventListener('cartUpdated', updateCount);
    };
  }, []);

  // Don't show this navbar on admin pages
  if (pathname?.startsWith('/admin')) {
    return null;
  }

  return (
    <header className="bg-shakti-cream/80 backdrop-blur-lg shadow-sm sticky top-0 z-50 border-b border-shakti-mitti/10 transition-all duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-4">
            <button className="lg:hidden text-shakti-dark"><Menu className="w-6 h-6" /></button>
            <Link href="/" className="text-3xl font-extrabold text-shakti-rust tracking-tight font-serif">शक्ति</Link>
          </div>

          <nav className="hidden lg:flex items-center gap-6 text-sm font-semibold text-shakti-dark">
            <Link href="/" className="hover:text-shakti-rust transition-colors uppercase tracking-widest relative group">Home<span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-shakti-rust transition-all group-hover:w-full"></span></Link>
            <Link href="/categories" className="hover:text-shakti-rust transition-colors uppercase tracking-widest relative group">Products<span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-shakti-rust transition-all group-hover:w-full"></span></Link>
            <Link href="/kahani" className="hover:text-shakti-rust transition-colors uppercase tracking-widest relative group">Kahani<span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-shakti-rust transition-all group-hover:w-full"></span></Link>
            <Link href="/contact" className="hover:text-shakti-rust transition-colors uppercase tracking-widest relative group">Contact<span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-shakti-rust transition-all group-hover:w-full"></span></Link>
          </nav>
        </div>

        <div className="hidden xl:flex flex-1 max-w-xl mx-8 relative">
          <input 
            type="text" 
            placeholder="Search our fresh, pure staples..." 
            className="w-full bg-white border border-shakti-mitti/30 rounded-full py-2.5 px-6 pl-12 focus:ring-2 focus:ring-shakti-sarson transition-all outline-none text-shakti-dark placeholder:text-shakti-mitti"
          />
          <Search className="w-5 h-5 text-shakti-mitti absolute left-4 top-1/2 -translate-y-1/2" />
        </div>

        <div className="flex items-center gap-6">
          {isLoggedIn ? (
            <Link href="/profile" className="text-shakti-dark hover:text-shakti-rust transition-colors flex items-center gap-1 text-sm font-semibold uppercase tracking-widest" title="Profile"><User className="w-6 h-6" /></Link>
          ) : (
            <Link href="/login" className="text-shakti-dark hover:text-shakti-rust transition-colors flex items-center gap-1 text-sm font-semibold uppercase tracking-widest"><User className="w-5 h-5" /> Sign In</Link>
          )}
          <Link href="/cart" className="text-shakti-dark hover:text-shakti-rust transition-colors relative">
            <ShoppingCart className="w-6 h-6" />
            {cartCount > 0 && (
              <span className="absolute -top-2 -right-2 bg-shakti-sarson text-shakti-dark text-xs font-extrabold rounded-full w-5 h-5 flex items-center justify-center">
                {cartCount}
              </span>
            )}
          </Link>
        </div>
      </div>

      {/* Mobile Search */}
      <div className="lg:hidden px-4 pb-4">
          <div className="relative">
          <input 
            type="text" 
            placeholder="Search staples..." 
            className="w-full bg-white border border-shakti-mitti/30 rounded-full py-2 px-4 pl-10 focus:ring-2 focus:ring-shakti-sarson outline-none text-shakti-dark placeholder:text-shakti-mitti"
          />
          <Search className="w-4 h-4 text-shakti-mitti absolute left-4 top-1/2 -translate-y-1/2" />
        </div>
      </div>
    </header>
  );
}

'use client';

import { Edit2, Eye, Trash2 } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useState } from 'react';

export default function CustomerActions({ customerId }: { customerId: number }) {
  const router = useRouter();
  const [isDeleting, setIsDeleting] = useState(false);

  const handleView = () => {
    router.push(`/admin/customers/${customerId}`);
  };

  const handleEdit = () => {
    router.push(`/admin/customers/${customerId}/edit`);
  };

  const handleDelete = async () => {
    if (!confirm('Are you sure you want to delete this customer?')) return;

    setIsDeleting(true);
    try {
      const res = await fetch(`http://localhost:4000/api/customers/${customerId}`, {
        method: 'DELETE',
      });
      const data = await res.json();

      if (!res.ok) {
        alert(data.error || 'Failed to delete customer');
      } else {
        router.refresh();
      }
    } catch (e) {
      alert('An error occurred while deleting the customer.');
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="flex items-center gap-3">
      <button 
        onClick={handleView}
        className="p-2 text-shakti-rust hover:bg-shakti-cream rounded-xl transition-colors group" 
        title="View Profile"
      >
        <Eye className="w-4 h-4 group-hover:text-shakti-dark" />
      </button>
      <button 
        onClick={handleEdit}
        className="p-2 text-shakti-rust hover:bg-shakti-cream rounded-xl transition-colors group" 
        title="Edit Customer"
      >
        <Edit2 className="w-4 h-4 group-hover:text-shakti-dark" />
      </button>
      <button 
        onClick={handleDelete}
        disabled={isDeleting}
        className="p-2 text-red-500 hover:bg-red-50 rounded-xl transition-colors group disabled:opacity-50" 
        title="Delete Customer"
      >
        <Trash2 className="w-4 h-4" />
      </button>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Save, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

export default function CustomerEditForm({ customer }: { customer: any }) {
  const [name, setName] = useState(customer.name || '');
  const [email, setEmail] = useState(customer.email || '');
  const [isSaving, setIsSaving] = useState(false);
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    try {
      const res = await fetch(`http://localhost:4000/api/customers/${customer.id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ name, email }),
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error || 'Failed to update customer');
      } else {
        router.push('/admin/customers');
        router.refresh();
      }
    } catch (error) {
      alert('Error updating customer');
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-[2rem] p-8 shadow-sm border border-shakti-mitti/10 max-w-2xl">
      <div className="space-y-6">
        <div>
          <label className="block text-sm font-bold text-shakti-dark mb-2">Full Name</label>
          <input 
            type="text" 
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full border border-shakti-mitti/20 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-shakti-rust bg-shakti-cream/30"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-bold text-shakti-dark mb-2">Email Address</label>
          <input 
            type="email" 
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full border border-shakti-mitti/20 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-shakti-rust bg-shakti-cream/30"
            required
          />
        </div>

        <div className="pt-4 flex items-center justify-end gap-4">
          <Link href="/admin/customers" className="px-6 py-3 rounded-xl font-bold text-shakti-dark hover:bg-shakti-cream transition-colors">
            Cancel
          </Link>
          <button 
            type="submit"
            disabled={isSaving}
            className="flex items-center gap-2 bg-shakti-dark text-white px-8 py-3 rounded-xl font-bold hover:bg-shakti-rust transition-colors disabled:opacity-70"
          >
            <Save className="w-5 h-5" /> {isSaving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </div>
    </form>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Eye, CheckCircle2, XCircle, MoreVertical, Loader2 } from 'lucide-react';

export default function OrderActions({ orderId, currentStatus }: { orderId: number, currentStatus: string }) {
  const router = useRouter();
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const updateStatus = async (status: string) => {
    if (status === currentStatus) return;

    setIsLoading(true);
    setIsOpen(false);
    try {
      const res = await fetch(`http://localhost:4000/api/orders/${orderId}/status`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status })
      });

      if (res.ok) {
        router.refresh();
      } else {
        alert('Failed to update status');
      }
    } catch (e) {
      alert('Error updating status');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative flex items-center gap-2">
      <button className="text-shakti-rust hover:text-shakti-dark flex items-center gap-1 font-bold transition-colors">
        <Eye className="w-4 h-4" /> View
      </button>

      <div className="relative">
        <button 
          onClick={() => setIsOpen(!isOpen)}
          disabled={isLoading}
          className="p-1 text-shakti-mitti hover:bg-shakti-cream rounded-full transition-colors disabled:opacity-50"
        >
          {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <MoreVertical className="w-5 h-5" />}
        </button>

        {isOpen && (
          <>
            <div className="fixed inset-0 z-10" onClick={() => setIsOpen(false)}></div>
            <div className="absolute right-0 top-full mt-1 w-40 bg-white rounded-xl shadow-lg border border-shakti-mitti/10 py-1 z-20">
              {['Processing', 'Shipped', 'Delivered', 'Cancelled'].map((status) => (
                <button
                  key={status}
                  onClick={() => updateStatus(status)}
                  className={`w-full text-left px-4 py-2 text-sm font-medium hover:bg-shakti-cream/50 transition-colors flex items-center justify-between ${currentStatus === status ? 'text-shakti-rust' : 'text-shakti-dark'}`}
                >
                  {status}
                  {currentStatus === status && <CheckCircle2 className="w-4 h-4 text-shakti-rust" />}
                </button>
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
}
